CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260612022618_InitialPostgres') THEN
    CREATE TABLE "ContactMessages" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "FullName" character varying(120) NOT NULL,
        "Phone" character varying(20) NOT NULL,
        "Email" character varying(200) NOT NULL,
        "Message" character varying(1000) NOT NULL,
        "CreatedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_ContactMessages" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260612022618_InitialPostgres') THEN
    CREATE TABLE "PriceItems" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "Name" character varying(160) NOT NULL,
        "PriceText" character varying(80) NOT NULL,
        "Note" character varying(300) NOT NULL,
        "SortOrder" integer NOT NULL,
        "IsActive" boolean NOT NULL,
        CONSTRAINT "PK_PriceItems" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260612022618_InitialPostgres') THEN
    CREATE TABLE "Roles" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "Name" character varying(80) NOT NULL,
        CONSTRAINT "PK_Roles" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260612022618_InitialPostgres') THEN
    CREATE TABLE "Services" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "Name" character varying(160) NOT NULL,
        "Description" character varying(600) NOT NULL,
        "IsActive" boolean NOT NULL,
        "SortOrder" integer NOT NULL,
        CONSTRAINT "PK_Services" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260612022618_InitialPostgres') THEN
    CREATE TABLE "StoreSettings" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "BrandName" character varying(160) NOT NULL,
        "Address" character varying(300) NOT NULL,
        "Hotline" character varying(30) NOT NULL,
        "ZaloUrl" character varying(200) NOT NULL,
        "FacebookUrl" character varying(200) NOT NULL,
        "OpeningHours" character varying(120) NOT NULL,
        "DeliveryPolicy" character varying(300) NOT NULL,
        CONSTRAINT "PK_StoreSettings" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260612022618_InitialPostgres') THEN
    CREATE TABLE "Users" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "UserName" character varying(80) NOT NULL,
        "PasswordHash" character varying(200) NOT NULL,
        "RoleId" integer NOT NULL,
        "IsActive" boolean NOT NULL,
        CONSTRAINT "PK_Users" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_Users_Roles_RoleId" FOREIGN KEY ("RoleId") REFERENCES "Roles" ("Id") ON DELETE CASCADE
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260612022618_InitialPostgres') THEN
    CREATE TABLE "Bookings" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "CustomerName" character varying(120) NOT NULL,
        "Phone" character varying(20) NOT NULL,
        "Address" character varying(500) NOT NULL,
        "AddressNote" character varying(300) NOT NULL,
        "ServiceId" integer NOT NULL,
        "EstimatedWeight" numeric(18,2),
        "PickupTime" timestamp with time zone NOT NULL,
        "Note" character varying(1000) NOT NULL,
        "Latitude" double precision,
        "Longitude" double precision,
        "DistanceKm" double precision,
        "RequiresDistanceConfirmation" boolean NOT NULL,
        "Status" character varying(40) NOT NULL,
        "CreatedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_Bookings" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_Bookings_Services_ServiceId" FOREIGN KEY ("ServiceId") REFERENCES "Services" ("Id") ON DELETE RESTRICT
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260612022618_InitialPostgres') THEN
    CREATE TABLE "BookingDetails" (
        "Id" integer GENERATED BY DEFAULT AS IDENTITY,
        "BookingId" integer NOT NULL,
        "ItemName" character varying(160) NOT NULL,
        "Quantity" integer NOT NULL,
        "Note" character varying(200) NOT NULL,
        CONSTRAINT "PK_BookingDetails" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_BookingDetails_Bookings_BookingId" FOREIGN KEY ("BookingId") REFERENCES "Bookings" ("Id") ON DELETE CASCADE
    );
    END IF;
END $EF$;

