DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260612022618_InitialPostgres') THEN
    PERFORM setval(
        pg_get_serial_sequence('"PriceItems"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "PriceItems") + 1,
            nextval(pg_get_serial_sequence('"PriceItems"', 'Id'))),
        false);
    PERFORM setval(
        pg_get_serial_sequence('"Roles"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "Roles") + 1,
            nextval(pg_get_serial_sequence('"Roles"', 'Id'))),
        false);
    PERFORM setval(
        pg_get_serial_sequence('"Services"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "Services") + 1,
            nextval(pg_get_serial_sequence('"Services"', 'Id'))),
        false);
    PERFORM setval(
        pg_get_serial_sequence('"StoreSettings"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "StoreSettings") + 1,
            nextval(pg_get_serial_sequence('"StoreSettings"', 'Id'))),
        false);
    PERFORM setval(
        pg_get_serial_sequence('"Users"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "Users") + 1,
            nextval(pg_get_serial_sequence('"Users"', 'Id'))),
        false);
    END IF;
END $EF$;

DO $EF$
